import { cleanup, render, screen } from '@solidjs/testing-library'
import { afterEach, describe, expect, it } from 'vitest'
import { createContext, useContext, type JSX } from 'solid-js'
import {
  Outlet,
  RouterProvider,
  createMemoryHistory,
  createRootRoute,
  createRoute,
  createRouter,
} from '../packages/solid-router/src'
import { StartClient } from '../packages/solid-start-client/src/StartClient'

const TestContext = createContext<string>()

function ContextWrap(props: { children?: JSX.Element }) {
  return (
    <TestContext.Provider value="wrapped">{props.children}</TestContext.Provider>
  )
}

function ContextConsumer() {
  const value = useContext(TestContext) ?? 'missing'
  return <div data-testid="context-value">{value}</div>
}

function createTestRouter(options: { wrap?: boolean; innerWrap?: boolean }) {
  const rootRoute = createRootRoute({ component: () => <Outlet /> })
  const indexRoute = createRoute({
    getParentRoute: () => rootRoute,
    path: '/',
    component: ContextConsumer,
  })

  return createRouter({
    routeTree: rootRoute.addChildren([indexRoute]),
    history: createMemoryHistory({ initialEntries: ['/'] }),
    ...(options.wrap ? { Wrap: ContextWrap } : {}),
    ...(options.innerWrap ? { InnerWrap: ContextWrap } : {}),
  })
}

afterEach(() => cleanup())

describe('temporary Wrap/InnerWrap reproduction', () => {
  it('RouterProvider Wrap provides context to route components', async () => {
    const router = createTestRouter({ wrap: true })
    render(() => <RouterProvider router={router} />)
    await expect.element(screen.findByTestId('context-value')).resolves.toHaveTextContent('wrapped')
  })

  it('RouterProvider InnerWrap provides context to route components', async () => {
    const router = createTestRouter({ innerWrap: true })
    render(() => <RouterProvider router={router} />)
    await expect.element(screen.findByTestId('context-value')).resolves.toHaveTextContent('wrapped')
  })

  it('StartClient Wrap provides context to route components', async () => {
    const router = createTestRouter({ wrap: true })
    await router.load()
    render(() => <StartClient router={router} />)
    await expect.element(screen.findByTestId('context-value')).resolves.toHaveTextContent('wrapped')
  })

  it('StartClient InnerWrap provides context to route components', async () => {
    const router = createTestRouter({ innerWrap: true })
    await router.load()
    render(() => <StartClient router={router} />)
    await expect.element(screen.findByTestId('context-value')).resolves.toHaveTextContent('wrapped')
  })
})

